18→  useEffect(() => {
19→    const interval = setInterval(() => {
20→      setProgress(prev => {
21→        if (prev >= 100) {
22→          clearInterval(interval);
23→          return 100;
24→        }
25→        return prev + 2;
26→      });
27→    }, 50);
