64→function App() {
65→  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);
66→  const [activeTab, setActiveTab] = useState('dashboard');
67→  const [showSplash, setShowSplash] = useState(true);
68→
69→  const handleLogin = (userData) => {
70→    localStorage.setItem('user', JSON.stringify(userData));
71→    setUser(userData);
72→  };
73→
74→  const handleLogout = () => {
75→    localStorage.removeItem('user');
76→    localStorage.removeItem('token');
77→    setUser(null);
78→    setActiveTab('dashboard');
79→  };
80→
81→  const renderContent = () => {
82→    switch (activeTab) {
83→      case 'dashboard': return <Dashboard user={user} />;
84→      case 'reports': return <ReportsPanel user={user} />;
85→      case 'mechanic': return <MechanicPanel user={user} />;
86→      case 'admin': return <AdminPanel user={user} />;
87→      case 'master': return <MasterPanel user={user} />;
88→      case 'nazoratchi': return <NazoratchiPanel user={user} />;
89→      case 'users': return <UsersPanel user={user} />;
90→      case 'asnova': return <AsnovaPanel user={user} />;
91→      default: return <Dashboard user={user} />;
92→    }
93→  };
94→
95→  if (showSplash) {
96→    return <SplashScreen onDone={() => setShowSplash(false)} />;
