98→
99→  return (
100→    <Router>
101→      <Routes>
102→        <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
103→        <Route path="/*" element={
104→          user ? (
105→            <div className="app-container app-appear">
106→              <Sidebar user={user} activeTab={activeTab} onTabChange={setActiveTab} onLogout={handleLogout} />
107→              <div className="main-content">
108→                {renderContent()}
109→              </div>
110→            </div>
111→          ) : (
112→            <Navigate to="/login" />
113→          )
114→        } />
115→      </Routes>
116→    </Router>
117→  );
118→}
119→
120→export default App;
